    const I = new Array(7);
    I[0] = 4 * r_curr + c_curr; // Start position (0, 0)

    for (let k = 0; k < 6; k++) {
        const move = directions[k];
        if (move === 'D') {
            r_curr += 1;
        } else { // 'R'
            c_curr += 1;
        }
        // Ensure we stay within bounds (although path length is 7, and directions implies valid moves)
        if (r_curr >= R_SIZE || c_curr >= C_SIZE) {
            // This case should not happen based on problem description constraints if moves are valid, 
            // but for safety in a real scenario, we might clip or handle errors.
            // Since the problem guarantees 3 D's and 3 R's, the final position is (3, 3).
        }
        I[k + 1] = 4 * r_curr + c_curr;
    }

    // M[j] = k if digit at index j (0-15) contributes to Vk. M[j] = -1 otherwise.
    const M = new Array(16).fill(-1);
    for (let k = 0; k < 7; k++) {
        M[I[k]] = k;
    }

    /**
     * Counts the number of non-negative 16-digit sequences (00...0 to S) 
     * that satisfy the non-decreasing path condition.
     * S must be a string of length 16.
     * @param {string} S 
     * @returns {number}
     */
    function count_up_to(S) {
        const N = 16;
        const memo = new Map();

        /**
         * DP(index, tight, last_V)
         * @param {number} index Current digit position being set (0 to 15)
         * @param {number} tight 1 if restricted by S, 0 otherwise
         * @param {number} last_V The value of the last determined path element (V_k). Range 0-9.
         * @returns {bigint} Count of valid completions
         */
        function dp(index, tight, last_V) {
            if (index === N) {
