            const limit = tight ? parseInt(S[index]) : 9;
            let count = 0n;

            for (let d = 0; d <= limit; d++) {
                let newTight = tight && (d === limit);
                let newLastV = last_V;
                let isValid = true;

                // Check if this digit contributes to the required path sequence
                const k = M[index];
                if (k !== -1) {
                    // This digit d is Vk. It must be >= V_{k-1}, which is tracked by last_V.
                    if (d < last_V) {
                        isValid = false;
                    } else {
                        // Update the tracking variable
                        newLastV = d;
                    }
                }

                if (isValid) {
                    count += dp(index + 1, newTight ? 1 : 0, newLastV);
                }
            }

            memo.set(key, count);
            return count;
        }

        // Initial call: index 0, tight 1, last_V 0 (since V0 >= 0 is always true)
        return dp(0, 1, 0);
    }

    // --- Step 2: Calculation for R ---

    // Pad R to 16 digits string
    let S_R = r.toString().padStart(16, '0');
    let countR = count_up_to(S_R);

    // --- Step 3: Calculation for L-1 ---

    // Calculate L-1
    let lMinus1;
    if (l === 0n) {
        lMinus1 = -1n;
    } else {
        lMinus1 = l - 1n;
